let currentScreen = 'title-screen';
let gameScore = 0;
let playerPos = {x:85,y:85};
let goalPos = {x:30,y:30};
const REQUIRED = ['memories','thank-you','game','honesty','future','photos'];
let visited = new Set(JSON.parse(localStorage.getItem('fqVisited')||'[]'));
let menuIdx = 0;
let lbIdx = 0;

// Stars
function initStars(){
  const c=document.getElementById('title-stars');
  if(!c)return;
  '★✦✧·*'.split('').concat(['★','✦','·','*','★','✦','·']).forEach((ch,i)=>{
    const s=document.createElement('span');
    s.textContent=ch; s.style.left=(Math.random()*90+5)+'%'; s.style.top=(Math.random()*90+5)+'%';
    s.style.fontSize=(6+Math.random()*8)+'px';
    s.style.animationDelay=(Math.random()*4)+'s'; s.style.animationDuration=(2+Math.random()*3)+'s';
    s.style.color=['#facc15','#4ade80','#f472b6','#60a5fa'][i%4];
    c.appendChild(s);
  });
}

// Nav
function navigate(target){
  document.querySelectorAll('.screen-content').forEach(s=>s.classList.remove('active'));
  document.getElementById(target).classList.add('active');
  currentScreen=target;
  if(target==='game')resetGame();
  else if(target==='photos')initPhotos();
  else if(target==='constellation')initConstellation();
  markVisited(target);
}

function goBack(){
  document.querySelectorAll('.screen-content').forEach(s=>s.classList.remove('active'));
  document.getElementById('title-screen').classList.add('active');
  document.querySelectorAll('.menu-item').forEach((i,x)=>i.classList.toggle('selected',x===0));
  currentScreen='title-screen'; menuIdx=0;
}

function initNav(){
  const items=Array.from(document.querySelectorAll('.menu-item'));
  items.forEach((item,idx)=>{
    item.setAttribute('tabindex','0');
    item.addEventListener('click',function(){
      items.forEach(i=>i.classList.remove('selected'));
      this.classList.add('selected'); menuIdx=idx;
      navigate(this.getAttribute('data-target'));
    });
  });
  document.addEventListener('keydown',e=>{
    if(currentScreen==='title-screen'){
      if(e.key==='ArrowUp'){menuIdx=(menuIdx-1+items.length)%items.length;items.forEach((i,x)=>i.classList.toggle('selected',x===menuIdx));e.preventDefault();}
      else if(e.key==='ArrowDown'){menuIdx=(menuIdx+1)%items.length;items.forEach((i,x)=>i.classList.toggle('selected',x===menuIdx));e.preventDefault();}
      else if(e.key==='Enter'||e.key===' '){items[menuIdx].click();e.preventDefault();}
    } else if(currentScreen==='game'){
      const map={'ArrowUp':[0,-10],'ArrowDown':[0,10],'ArrowLeft':[-10,0],'ArrowRight':[10,0]};
      if(map[e.key]){movePlayer(...map[e.key]);e.preventDefault();}
    }
    if(document.getElementById('lightbox').classList.contains('open')){
      if(e.key==='Escape')closeLb();
      if(e.key==='ArrowLeft'){lbIdx=(lbIdx-1+PHOTOS.length)%PHOTOS.length;updateLb();}
      if(e.key==='ArrowRight'){lbIdx=(lbIdx+1)%PHOTOS.length;updateLb();}
    }
  });
}

// Game
function initGame(){
  document.getElementById('up').addEventListener('click',()=>movePlayer(0,-10));
  document.getElementById('down').addEventListener('click',()=>movePlayer(0,10));
  document.getElementById('left').addEventListener('click',()=>movePlayer(-10,0));
  document.getElementById('right').addEventListener('click',()=>movePlayer(10,0));
  updatePlayerPos(); updateGoalPos();
}

function movePlayer(dx,dy){
  if(currentScreen!=='game')return;
  const trail=document.createElement('div'); trail.className='game-trail';
  trail.style.left=playerPos.x+6+'px'; trail.style.top=playerPos.y+6+'px';
  document.getElementById('game-area').appendChild(trail);
  setTimeout(()=>trail.remove(),500);
  playerPos.x=Math.max(0,Math.min(262,playerPos.x+dx));
  playerPos.y=Math.max(20,Math.min(290,playerPos.y+dy));
  updatePlayerPos(); checkWin();
}
function updatePlayerPos(){const p=document.getElementById('player');p.style.left=playerPos.x+'px';p.style.top=playerPos.y+'px';}
function updateGoalPos(){const g=document.getElementById('goal');g.style.left=goalPos.x+'px';g.style.top=goalPos.y+'px';}
function checkWin(){
  if(Math.hypot(playerPos.x-goalPos.x,playerPos.y-goalPos.y)<20){
    gameScore++; document.getElementById('score').textContent=gameScore;
    document.getElementById('game-message').textContent='✦ FRIENDSHIP POWER! ✦';
    localStorage.setItem('fqScore',gameScore);
    setTimeout(()=>{
      goalPos.x=10+Math.floor(Math.random()*250); goalPos.y=30+Math.floor(Math.random()*260);
      updateGoalPos(); document.getElementById('game-message').textContent='REACH THE ★ GOAL!';
    },1200);
  }
}
function resetGame(){
  playerPos={x:85,y:85}; goalPos={x:30,y:30};
  updatePlayerPos(); updateGoalPos();
  document.getElementById('game-message').textContent='REACH THE ★ GOAL!';
  const s=localStorage.getItem('fqScore'); if(s){gameScore=parseInt(s);document.getElementById('score').textContent=gameScore;}
}

// Photos
function initPhotos(){
  const grid=document.getElementById('photo-grid'); grid.innerHTML='';
  PHOTOS.forEach((p,i)=>{
    const div=document.createElement('div'); div.className='photo-thumb'; div.setAttribute('tabindex','0');
    const img=document.createElement('img'); img.src=p.src; img.alt=p.label; img.loading='lazy';
    const lbl=document.createElement('div'); lbl.className='lbl'; lbl.textContent=p.label;
    div.appendChild(img); div.appendChild(lbl);
    div.addEventListener('click',()=>openLb(i));
    div.addEventListener('keydown',e=>{if(e.key==='Enter')openLb(i);});
    grid.appendChild(div);
  });
}

function openLb(idx){lbIdx=idx; updateLb(); document.getElementById('lightbox').classList.add('open');}
function closeLb(){document.getElementById('lightbox').classList.remove('open');}
function updateLb(){
  const p=PHOTOS[lbIdx];
  document.getElementById('lb-img').src=p.src;
  document.getElementById('lb-label').textContent=p.label;
  
  document.getElementById('lb-counter').textContent=(lbIdx+1)+' / '+PHOTOS.length;
}

// Constellation
let constellationInitialized = false;
function initConstellation() {
  const canvas = document.getElementById('stardust-lines');
  const ctx = canvas.getContext('2d');
  const wrapper = document.getElementById('stars-wrapper');
  const message = document.getElementById('final-message');
  const screenEl = document.getElementById('constellation');

  // Always resize canvas to match current screen size (fixes 0x0 on first load)
  function resizeCanvas(){
    canvas.width = screenEl.offsetWidth || window.innerWidth;
    canvas.height = screenEl.offsetHeight || window.innerHeight;
    drawLines();
  }

  if(constellationInitialized){ resizeCanvas(); return; }
  constellationInitialized = true;

  // Background stars
  for(let i=0;i<80;i++){
    let s=document.createElement('div');
    s.style.cssText=`position:absolute;background:white;border-radius:50%;width:${Math.random()*2+1}px;height:${Math.random()*2+1}px;left:${Math.random()*100}%;top:${Math.random()*100}%;opacity:${0.2+Math.random()*0.5};`;
    wrapper.appendChild(s);
  }

  // F1T3 constellation coords — fixed T shape (no duplicate x positions)
  const starsData = [
    // F
    {id:0,x:10,y:28},{id:1,x:20,y:28}, // top bar of F
    {id:2,x:10,y:45},{id:3,x:17,y:45}, // mid bar of F
    {id:4,x:10,y:62},                   // bottom of F
    // 1
    {id:5,x:35,y:28},{id:6,x:35,y:62}, // vertical stroke of 1
    // T
    {id:7,x:50,y:28},{id:8,x:65,y:28}, // top bar of T
    {id:9,x:57,y:28},{id:10,x:57,y:62},// centre down of T
    // 3
    {id:11,x:75,y:28},{id:12,x:85,y:28}, // top of 3
    {id:13,x:85,y:45},{id:14,x:75,y:45}, // mid of 3
    {id:15,x:85,y:62},{id:16,x:75,y:62}  // bottom of 3
  ];
  const connections = [
    [0,1],[0,2],[2,3],[2,4],       // F
    [5,6],                          // 1
    [7,8],[9,10],                   // T (top bar + vertical)
    [7,9],                          // connect T bar to stem
    [11,12],[12,13],[13,14],[13,15],[15,16] // 3
  ];

  let activeStars = new Set();
  const domStars = [];

  starsData.forEach(data=>{
    let star=document.createElement('div');
    star.style.cssText=`position:absolute;width:14px;height:14px;background:#c5c6c7;border-radius:50%;left:${data.x}%;top:${data.y}%;transform:translate(-50%,-50%);cursor:pointer;box-shadow:0 0 8px #fff;transition:all 0.3s ease;z-index:5;`;
    star.addEventListener('click',()=>{
      if(!activeStars.has(data.id)){
        activeStars.add(data.id);
        star.style.background='#66fcf1';
        star.style.boxShadow='0 0 15px #66fcf1, 0 0 30px #66fcf1';
        star.style.transform='translate(-50%,-50%) scale(1.4)';
        drawLines(); checkComplete();
      }
    });
    domStars[data.id]=star;
    wrapper.appendChild(star);
  });

  function drawLines(){
    ctx.clearRect(0,0,canvas.width,canvas.height);
    ctx.strokeStyle='rgba(102,252,241,0.7)';
    ctx.lineWidth=2;ctx.lineCap='round';
    ctx.shadowBlur=12;ctx.shadowColor='#66fcf1';
    connections.forEach(([sId,eId])=>{
      if(activeStars.has(sId)&&activeStars.has(eId)){
        const sr=domStars[sId].getBoundingClientRect();
        const er=domStars[eId].getBoundingClientRect();
        const cr=canvas.getBoundingClientRect();
        ctx.beginPath();
        ctx.moveTo(sr.left-cr.left+sr.width/2, sr.top-cr.top+sr.height/2);
        ctx.lineTo(er.left-cr.left+er.width/2, er.top-cr.top+er.height/2);
        ctx.stroke();
      }
    });
  }

  function checkComplete(){
    if(activeStars.size===starsData.length){
      document.getElementById('const-hint').style.opacity='0';
      setTimeout(()=>{ message.style.opacity='1'; },800);
    }
  }

  // Resize after a short delay to ensure screen is fully visible and has dimensions
  setTimeout(resizeCanvas, 100);
  window.addEventListener('resize', resizeCanvas);
}

// Buttons
function initButtons(){
  document.getElementById('a-button').addEventListener('click',()=>{
    if(currentScreen==='game'){document.getElementById('game-message').textContent='★ GO GO GO! ★';setTimeout(()=>document.getElementById('game-message').textContent='REACH THE ★ GOAL!',1000);}
  });
  document.getElementById('b-button').addEventListener('click',goBack);
  document.getElementById('start').addEventListener('click',()=>alert('FRIENDSHIP QUEST\nF1T3 · Class of 2024\n\nVisit ALL 6 sections to unlock the 🎁 present!\n\nD-PAD: Move in game\nA: Action / B: Back to menu'));
  document.getElementById('select').addEventListener('click',()=>{
    const sc=REQUIRED[Math.floor(Math.random()*REQUIRED.length)];
    navigate(sc);
    document.querySelectorAll('.menu-item').forEach(i=>i.classList.toggle('selected',i.getAttribute('data-target')===sc));
  });
  document.getElementById('save-honesty').addEventListener('click', submitHonestyMessage);
  document.getElementById('lb-close').addEventListener('click',closeLb);
  document.getElementById('lb-prev').addEventListener('click',()=>{lbIdx=(lbIdx-1+PHOTOS.length)%PHOTOS.length;updateLb();});
  document.getElementById('lb-next').addEventListener('click',()=>{lbIdx=(lbIdx+1)%PHOTOS.length;updateLb();});
  document.getElementById('lightbox').addEventListener('click',e=>{if(e.target===document.getElementById('lightbox'))closeLb();});
  document.getElementById('reset-present').addEventListener('click',()=>{
    visited=new Set(); localStorage.removeItem('fqVisited');
    document.getElementById('present').dataset.unlocked='';
    updatePresent(); updateProgress();
  });
}

// Present
function initPresent(){
  updatePresent();
  const pr=document.getElementById('present');
  pr.addEventListener('click',()=>{
    if(!isUnlocked()){pr.classList.add('shake');setTimeout(()=>pr.classList.remove('shake'),400);return;}
    document.getElementById('present-overlay').classList.remove('hidden');
    const fc = document.getElementById('flower-container');
    if(!fc.dataset.started){
      fc.dataset.started='1';
      setTimeout(()=>fc.classList.remove('not-loaded'), 1000);
    }
  });
  pr.addEventListener('keydown',e=>{if(e.key==='Enter')pr.click();});
  document.getElementById('present-close').addEventListener('click',()=>{
    document.getElementById('present-overlay').classList.add('hidden');
  });
}
function isUnlocked(){return REQUIRED.every(s=>visited.has(s));}
function markVisited(id){
  if(!REQUIRED.includes(id))return;
  visited.add(id); localStorage.setItem('fqVisited',JSON.stringify([...visited]));
  updatePresent(); updateProgress();
}
function updatePresent(){
  const pr=document.getElementById('present');
  if(isUnlocked()){
    pr.classList.remove('locked');
    if(!pr.dataset.unlocked){pr.dataset.unlocked='1';confetti(pr);}
  }else{pr.classList.add('locked');}
}
function updateProgress(){
  const p=document.getElementById('present-progress'); if(p)p.textContent=visited.size+'/6';
  const l=document.getElementById('present-live'); if(l)l.textContent=isUnlocked()?'Present unlocked!':visited.size+' of 6 visited.';
}
function confetti(el){
  const colors=['#facc15','#4ade80','#f472b6','#60a5fa','#f97316'];
  const r=el.getBoundingClientRect();
  for(let i=0;i<24;i++){
    const c=document.createElement('div'); c.className='confetti-piece';
    c.style.background=colors[i%colors.length];
    c.style.left=(r.left+r.width/2+(Math.random()-0.5)*80)+'px';
    c.style.top=(r.top+r.height/2)+'px';
    c.style.animationDelay=(Math.random()*0.3)+'s';
    document.body.appendChild(c); setTimeout(()=>c.remove(),2500);
  }
}

// Load saved
function loadSaved(){
  const h=localStorage.getItem('fqHonesty'); if(h)document.getElementById('honesty-input').value=h;
  const s=localStorage.getItem('fqScore'); if(s){gameScore=parseInt(s);document.getElementById('score').textContent=gameScore;}
}

