async function supabaseFetch(method, body = null) {
  const opts = {
    method,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': 'Bearer ' + SUPABASE_KEY,
      'Content-Type': 'application/json',
      'Prefer': method === 'POST' ? 'return=minimal' : ''
    }
  };
  if (body) opts.body = JSON.stringify(body);
  const url = SUPABASE_URL + '/rest/v1/honesty_messages' + (method === 'GET' ? '?select=message,created_at&order=created_at.desc' : '');
  const res = await fetch(url, opts);
  if (method === 'GET') return await res.json();
  if (!res.ok) {
    const errText = await res.text();
    throw new Error('Supabase error ' + res.status + ': ' + errText);
  }
  return true;
}

async function loadHonestyMessages() {
  const list = document.getElementById('honesty-messages-list');
  if (!list) return;
  list.innerHTML = '<div style="font-size:6px;color:rgba(74,222,128,0.5);font-family:var(--text-mono);">Loading...</div>';
  try {
    const data = await supabaseFetch('GET');
    if (!data || data.length === 0) {
      list.innerHTML = '<div style="font-size:6px;color:rgba(74,222,128,0.4);font-family:var(--text-mono);padding:4px;">Belum ada mesej lagi. Jadilah yang pertama! 💬</div>';
      return;
    }
    list.innerHTML = data.map((d, i) => `
      <div style="background:rgba(74,222,128,0.05);border:1px solid rgba(74,222,128,0.15);border-left:2px solid var(--gb-pink);border-radius:0 4px 4px 0;padding:6px 8px;margin-bottom:6px;">
        <div style="font-size:5px;color:rgba(74,222,128,0.4);font-family:var(--text-mono);margin-bottom:3px;">ANON #${i+1}</div>
        <div style="font-size:6px;color:rgba(74,222,128,0.85);font-family:var(--text-mono);line-height:1.7;">${d.message}</div>
      </div>
    `).join('');
  } catch(e) {
    list.innerHTML = '<div style="font-size:6px;color:rgba(244,114,182,0.7);font-family:var(--text-mono);">Could not load messages.</div>';
  }
}

async function submitHonestyMessage() {
  const input = document.getElementById('honesty-input');
  const btn = document.getElementById('save-honesty');
  const msg = input.value.trim();
  if (!msg) return;
  btn.textContent = '⏳ SENDING...';
  btn.disabled = true;
  try {
    const ok = await supabaseFetch('POST', { message: msg });
    if (ok) {
      input.value = '';
      btn.textContent = '✓ SENT!';
      await loadHonestyMessages();
    } else {
      btn.textContent = '✗ FAILED';
    }
  } catch(e) {
    btn.textContent = '✗ ERROR';
    const list = document.getElementById('honesty-messages-list');
    if(list) list.innerHTML = '<div style="font-size:6px;color:#f472b6;font-family:var(--text-mono);padding:4px;line-height:1.8;">' + e.message + '</div>';
  }
  setTimeout(() => { btn.textContent = '💾 SEND'; btn.disabled = false; }, 2000);
}


// ── Background Music ──
(function () {
  const audio = document.getElementById('bgm');
  const btn   = document.getElementById('music-toggle');
  let playing = false;

  function startMusic() {
    audio.volume = 0.45;
    audio.play().then(() => {
      playing = true;
      btn.textContent = '🎵';
      btn.classList.remove('muted');
    }).catch(() => {});
  }

  function toggleMusic() {
    if (playing) {
      audio.pause();
      playing = false;
      btn.textContent = '🔇';
      btn.classList.add('muted');
    } else {
      startMusic();
    }
  }

  btn.addEventListener('click', toggleMusic);

  // Auto-play on first user interaction with the page
  function handleFirstInteraction() {
    startMusic();
    document.removeEventListener('click', handleFirstInteraction);
    document.removeEventListener('keydown', handleFirstInteraction);
    document.removeEventListener('touchstart', handleFirstInteraction);
  }

  document.addEventListener('click', handleFirstInteraction);
  document.addEventListener('keydown', handleFirstInteraction);
  document.addEventListener('touchstart', handleFirstInteraction);
})();
